import type {
  AdapterCapabilities,
  AdapterCategory,
  AdapterSubscription,
  ConnectionStatus,
  ExchangeAdapter,
  ExchangeConfig,
  HealthMetrics,
  OHLCVCallback,
  OrderbookCallback,
  StatusCallback,
  TickerCallback,
  TradeCallback,
} from '../../types/adapter';
import type { NormalizedOHLCV, NormalizedOrderbook, NormalizedSymbol, NormalizedTrade, Timeframe } from '../../types/normalized';
import { createSubscriptionId, parseNumeric } from '../../normalization/pipeline';
import { RateLimiter, EXCHANGE_RATE_LIMITS } from '../../rate-limiter/rate-limiter';
import { CoinbaseNormalizer } from './coinbase-normalizer';
import type { CoinbaseGranularity, CoinbaseProduct, CoinbaseRestCandle, CoinbaseRawMessage } from './coinbase-types';

import { CircuitBreaker } from '../../circuit-breaker/circuit-breaker';

const DEFAULT_WS_URL = 'wss://advanced-trade-ws.coinbase.com';
const DEFAULT_REST_URL = 'https://api.coinbase.com';

/** JWT refresh interval in milliseconds (2 minutes). */
const JWT_REFRESH_MS = 2 * 60 * 1000;

/** Default heartbeat timeout for Coinbase (60 seconds). */
const DEFAULT_HEARTBEAT_TIMEOUT_MS = 60_000;

/** Timeframe to Coinbase granularity mapping. */
const GRANULARITY_MAP: Partial<Record<Timeframe, CoinbaseGranularity>> = {
  '1m': 'ONE_MINUTE',
  '5m': 'FIVE_MINUTE',
  '15m': 'FIFTEEN_MINUTE',
  '30m': 'THIRTY_MINUTE',
  '1h': 'ONE_HOUR',
  '2h': 'TWO_HOUR',
  '6h': 'SIX_HOUR',
  '1d': 'ONE_DAY',
};

interface ActiveSubscription {
  readonly id: string;
  readonly symbol: string;
  readonly channel: string;
  readonly type: 'ticker' | 'orderbook' | 'trades' | 'ohlcv' | 'status';
  readonly callback: TickerCallback | OrderbookCallback | TradeCallback | OHLCVCallback | StatusCallback;
}

/**
 * Coinbase Advanced Trade exchange adapter.
 *
 * Features:
 * - JWT authentication with auto-refresh every 2 minutes
 * - Sequence number gap detection with automatic re-subscription
 * - L2 order book state management
 * - Rate-limited REST API calls
 */
export class CoinbaseAdapter implements ExchangeAdapter {
  readonly exchangeId = 'coinbase' as const;
  readonly displayName = 'Coinbase';
  readonly category: AdapterCategory = 'cex';
  readonly capabilities: AdapterCapabilities = {
    realtime: true,
    historicalDepth: '7y',
    orderbook: true,
    trades: true,
    ohlcv: true,
    fundingRates: false,
    openInterest: false,
    liquidations: false,
    defiMetrics: false,
    onChainMetrics: false,
    authenticated: true,
  };

  private ws: WebSocket | null = null;
  private config: ExchangeConfig | null = null;
  private readonly normalizer = new CoinbaseNormalizer();
  private rateLimiter: RateLimiter | null = null;
  private readonly subscriptions = new Map<string, ActiveSubscription>();
  private readonly statusCallbacks = new Map<string, StatusCallback>();
  private connectionState: ConnectionStatus = {
    state: 'disconnected',
    latencyMs: 0,
    messagesPerSecond: 0,
    lastMessageAt: 0,
    reconnectAttempt: 0,
    uptime: 0,
  };
  private connectTime = 0;
  private reconnectAttempt = 0;
  private reconnectTimer: ReturnType<typeof setTimeout> | undefined;
  private jwtRefreshTimer: ReturnType<typeof setTimeout> | undefined;
  private messageCount = 0;
  private messageRateWindowStart = 0;
  private readonly circuitBreaker = new CircuitBreaker();
  private heartbeatTimer: ReturnType<typeof setTimeout> | undefined;
  private heartbeatTimeoutMs = DEFAULT_HEARTBEAT_TIMEOUT_MS;
  private totalErrors = 0;
  private totalRequests = 0;

  async connect(config: ExchangeConfig): Promise<void> {
    this.config = config;
    this.heartbeatTimeoutMs = config.heartbeatTimeoutMs ?? DEFAULT_HEARTBEAT_TIMEOUT_MS;
    if (config.circuitBreaker) {
      this.circuitBreaker.reset();
    }
    const rateLimitConfig = EXCHANGE_RATE_LIMITS['coinbase'];
    if (rateLimitConfig) {
      this.rateLimiter = new RateLimiter('coinbase', rateLimitConfig);
    }
    await this.circuitBreaker.execute(() => this.establishConnection());
  }

  async disconnect(): Promise<void> {
    this.clearTimers();
    this.stopHeartbeat();
    if (this.ws) {
      this.ws.onclose = null;
      this.ws.onerror = null;
      this.ws.onmessage = null;
      this.ws.close();
      this.ws = null;
    }
    this.subscriptions.clear();
    this.statusCallbacks.clear();
    this.rateLimiter?.dispose();
    this.rateLimiter = null;
    this.normalizer.resetSequence();
    this.circuitBreaker.reset();
    this.updateState('disconnected');
  }

  getStatus(): ConnectionStatus {
    return { ...this.connectionState, uptime: this.getUptime() };
  }

  getHealthMetrics(): HealthMetrics {
    const status = this.getStatus();
    const uptimeSeconds = status.uptime;
    const uptimePercent = uptimeSeconds > 0
      ? Math.min(100, (uptimeSeconds / (uptimeSeconds + this.reconnectAttempt * 5)) * 100)
      : 0;
    return {
      connected: status.state === 'connected',
      latencyMs: status.latencyMs,
      messagesPerSecond: status.messagesPerSecond,
      uptimePercent,
      lastMessageAt: status.lastMessageAt,
      errorRate: this.totalRequests > 0 ? this.totalErrors / this.totalRequests : 0,
      circuitBreakerState: this.circuitBreaker.state,
    };
  }

  onStatusChange(callback: StatusCallback): AdapterSubscription {
    const id = createSubscriptionId('coinbase', 'status', '_global');
    this.statusCallbacks.set(id, callback);
    return {
      id,
      symbol: '_global',
      type: 'status',
      dispose: () => { this.statusCallbacks.delete(id); },
    };
  }

  subscribeTicker(symbol: string, callback: TickerCallback): AdapterSubscription {
    const productId = this.toProductId(symbol);
    return this.addSubscription(symbol, 'ticker', productId, 'ticker', callback);
  }

  subscribeOrderbook(symbol: string, _depth: number, callback: OrderbookCallback): AdapterSubscription {
    const productId = this.toProductId(symbol);
    return this.addSubscription(symbol, 'level2', productId, 'orderbook', callback);
  }

  subscribeTrades(symbol: string, callback: TradeCallback): AdapterSubscription {
    const productId = this.toProductId(symbol);
    return this.addSubscription(symbol, 'market_trades', productId, 'trades', callback);
  }

  subscribeOHLCV(symbol: string, _timeframe: Timeframe, callback: OHLCVCallback): AdapterSubscription {
    const productId = this.toProductId(symbol);
    return this.addSubscription(symbol, 'candles', productId, 'ohlcv', callback);
  }

  async getCandles(symbol: string, timeframe: Timeframe, from: number, to: number): Promise<NormalizedOHLCV[]> {
    const productId = this.toProductId(symbol);
    const granularity = GRANULARITY_MAP[timeframe];
    if (!granularity) {
      throw new Error(`Unsupported timeframe for Coinbase: ${timeframe}`);
    }
    const startSec = Math.floor(from / 1000);
    const endSec = Math.floor(to / 1000);
    const url = `${this.getRestUrl()}/api/v3/brokerage/market/products/${productId}/candles?start=${startSec}&end=${endSec}&granularity=${granularity}`;

    await this.rateLimiter?.acquire();
    const response = await fetch(url);
    if (!response.ok) {
      throw new Error(`Coinbase REST error: ${response.status} ${response.statusText}`);
    }
    const data = await response.json() as { candles: CoinbaseRestCandle[] };
    return data.candles.map(c => this.normalizer.normalizeRestCandle(c));
  }

  async getOrderbookSnapshot(symbol: string, depth: number): Promise<NormalizedOrderbook> {
    const productId = this.toProductId(symbol);
    const limit = Math.min(depth, 500);
    const url = `${this.getRestUrl()}/api/v3/brokerage/market/products/${productId}/book?limit=${limit}`;

    await this.rateLimiter?.acquire();
    const response = await fetch(url);
    if (!response.ok) {
      throw new Error(`Coinbase REST error: ${response.status} ${response.statusText}`);
    }
    const data = await response.json() as {
      pricebook: {
        bids: Array<{ price: string; size: string }>;
        asks: Array<{ price: string; size: string }>;
      };
    };

    return {
      symbol: this.normalizeSymbol(productId),
      timestamp: Date.now(),
      bids: data.pricebook.bids.map(b => ({
        price: parseNumeric(b.price),
        quantity: parseNumeric(b.size),
      })),
      asks: data.pricebook.asks.map(a => ({
        price: parseNumeric(a.price),
        quantity: parseNumeric(a.size),
      })),
      sequenceId: 0,
      type: 'snapshot',
    };
  }

  async getRecentTrades(symbol: string, limit: number): Promise<NormalizedTrade[]> {
    const productId = this.toProductId(symbol);
    const url = `${this.getRestUrl()}/api/v3/brokerage/market/products/${productId}/ticker?limit=${Math.min(limit, 300)}`;

    await this.rateLimiter?.acquire();
    const response = await fetch(url);
    if (!response.ok) {
      throw new Error(`Coinbase REST error: ${response.status} ${response.statusText}`);
    }
    const data = await response.json() as {
      trades: Array<{
        trade_id: string;
        product_id: string;
        price: string;
        size: string;
        time: string;
        side: 'BUY' | 'SELL';
      }>;
    };

    return data.trades.map(t => ({
      id: t.trade_id,
      timestamp: Date.parse(t.time),
      price: parseNumeric(t.price),
      quantity: parseNumeric(t.size),
      side: t.side === 'BUY' ? 'buy' as const : 'sell' as const,
      buyerMaker: t.side === 'SELL',
    }));
  }

  async getSymbols(): Promise<NormalizedSymbol[]> {
    const url = `${this.getRestUrl()}/api/v3/brokerage/market/products`;

    await this.rateLimiter?.acquire();
    const response = await fetch(url);
    if (!response.ok) {
      throw new Error(`Coinbase REST error: ${response.status} ${response.statusText}`);
    }
    const data = await response.json() as { products: CoinbaseProduct[] };

    return data.products
      .filter(p => !p.trading_disabled && p.status === 'online')
      .map(p => this.normalizeProductInfo(p));
  }

  private normalizeProductInfo(raw: CoinbaseProduct): NormalizedSymbol {
    const parts = raw.product_id.split('-');
    const base = parts[0] ?? raw.base_currency_id;
    const quote = parts[1] ?? raw.quote_currency_id;

    return {
      symbol: `${base}/${quote}`,
      base,
      quote,
      exchangeSymbol: raw.product_id,
      exchangeId: 'coinbase',
      type: 'spot',
      pricePrecision: this.countDecimals(raw.quote_increment),
      quantityPrecision: this.countDecimals(raw.base_increment),
      minQuantity: parseNumeric(raw.base_min_size),
      tickSize: parseNumeric(raw.quote_increment),
      active: !raw.trading_disabled,
    };
  }

  private countDecimals(value: string): number {
    const parts = value.split('.');
    return parts[1]?.length ?? 0;
  }

  private addSubscription(
    symbol: string,
    channel: string,
    productId: string,
    type: 'ticker' | 'orderbook' | 'trades' | 'ohlcv',
    callback: TickerCallback | OrderbookCallback | TradeCallback | OHLCVCallback,
  ): AdapterSubscription {
    const id = createSubscriptionId('coinbase', type, symbol);
    const sub: ActiveSubscription = { id, symbol, channel, type, callback };
    this.subscriptions.set(id, sub);

    if (this.ws?.readyState === WebSocket.OPEN) {
      this.sendSubscribe(channel, [productId]);
    }

    return {
      id,
      symbol,
      type,
      dispose: () => {
        this.subscriptions.delete(id);
        const stillUsed = Array.from(this.subscriptions.values())
          .some(s => s.channel === channel && s.symbol === symbol);
        if (!stillUsed && this.ws?.readyState === WebSocket.OPEN) {
          this.sendUnsubscribe(channel, [productId]);
        }
      },
    };
  }

  private async establishConnection(): Promise<void> {
    this.updateState('connecting');
    const wsUrl = this.config?.wsUrl ?? DEFAULT_WS_URL;

    return new Promise<void>((resolve, reject) => {
      try {
        this.ws = new WebSocket(wsUrl);
      } catch (err) {
        this.updateState('error', err instanceof Error ? err.message : 'WebSocket creation failed');
        reject(err);
        return;
      }

      this.ws.onopen = () => {
        this.connectTime = Date.now();
        this.reconnectAttempt = 0;
        this.messageRateWindowStart = Date.now();
        this.messageCount = 0;
        this.normalizer.resetSequence();
        this.updateState('connected');
        this.startHeartbeat();
        this.resubscribeAll();

        if (this.config?.apiKey && this.config?.apiSecret) {
          this.jwtRefreshTimer = setInterval(() => {
            this.resubscribeAll();
          }, JWT_REFRESH_MS);
        }

        resolve();
      };

      this.ws.onmessage = (event: MessageEvent) => {
        this.handleMessage(event.data as string);
      };

      this.ws.onerror = () => {
        this.updateState('error', 'WebSocket error');
      };

      this.ws.onclose = () => {
        if (this.connectionState.state !== 'disconnected') {
          this.reconnect();
        }
      };
    });
  }

  private handleMessage(rawData: string): void {
    this.messageCount++;
    this.resetHeartbeat();
    const now = Date.now();
    const elapsed = now - this.messageRateWindowStart;
    if (elapsed >= 10_000) {
      this.connectionState = {
        ...this.connectionState,
        messagesPerSecond: this.messageCount / (elapsed / 1000),
        lastMessageAt: now,
      };
      this.messageCount = 0;
      this.messageRateWindowStart = now;
    }

    const message = this.normalizer.parseMessage(rawData);
    if (!message) return;

    // Check for sequence gaps
    if (this.normalizer.hasSequenceGap(message.sequence_num)) {
      this.resubscribeAll();
      return;
    }

    for (const sub of this.subscriptions.values()) {
      switch (sub.type) {
        case 'ticker': {
          const tick = this.normalizer.normalizeTicker(message);
          if (tick) (sub.callback as TickerCallback)(tick);
          break;
        }
        case 'trades': {
          const trade = this.normalizer.normalizeTrade(message);
          if (trade) (sub.callback as TradeCallback)(trade);
          break;
        }
        case 'ohlcv': {
          const candle = this.normalizer.normalizeOHLCV(message);
          if (candle) (sub.callback as OHLCVCallback)(candle);
          break;
        }
        case 'orderbook': {
          const book = this.normalizer.normalizeOrderbook(message);
          if (book) (sub.callback as OrderbookCallback)(book);
          break;
        }
      }
    }
  }

  private resubscribeAll(): void {
    if (!this.ws || this.ws.readyState !== WebSocket.OPEN) return;
    const channelProducts = new Map<string, Set<string>>();
    for (const sub of this.subscriptions.values()) {
      const productId = this.toProductId(sub.symbol);
      let products = channelProducts.get(sub.channel);
      if (!products) {
        products = new Set<string>();
        channelProducts.set(sub.channel, products);
      }
      products.add(productId);
    }
    for (const [channel, products] of channelProducts) {
      this.sendSubscribe(channel, Array.from(products));
    }
  }

  private reconnect(): void {
    if (this.connectionState.state === 'disconnected') return;
    this.clearTimers();
    this.stopHeartbeat();
    this.circuitBreaker.recordFailure();

    if (this.ws) {
      this.ws.onclose = null;
      this.ws.onerror = null;
      this.ws.onmessage = null;
      this.ws.close();
      this.ws = null;
    }

    this.reconnectAttempt++;
    this.totalErrors++;
    this.updateState('reconnecting');

    const baseDelay = Math.min(1000 * Math.pow(2, this.reconnectAttempt - 1), 16_000);
    const jitter = Math.random() * baseDelay * 0.25;
    const delay = this.reconnectAttempt === 1 ? 0 : baseDelay + jitter;

    this.reconnectTimer = setTimeout(() => {
      this.circuitBreaker.execute(() => this.establishConnection()).catch(() => {
        this.reconnect();
      });
    }, delay);
  }

  private sendSubscribe(channel: string, productIds: string[]): void {
    if (!this.ws || this.ws.readyState !== WebSocket.OPEN) return;
    this.ws.send(JSON.stringify({
      type: 'subscribe',
      product_ids: productIds,
      channel,
    }));
  }

  private sendUnsubscribe(channel: string, productIds: string[]): void {
    if (!this.ws || this.ws.readyState !== WebSocket.OPEN) return;
    this.ws.send(JSON.stringify({
      type: 'unsubscribe',
      product_ids: productIds,
      channel,
    }));
  }

  private updateState(state: ConnectionStatus['state'], errorMessage?: string): void {
    this.connectionState = {
      state,
      latencyMs: this.connectionState.latencyMs,
      messagesPerSecond: this.connectionState.messagesPerSecond,
      lastMessageAt: this.connectionState.lastMessageAt,
      errorMessage,
      reconnectAttempt: this.reconnectAttempt,
      uptime: this.getUptime(),
    };
    for (const callback of this.statusCallbacks.values()) {
      callback(this.connectionState);
    }
  }

  private getUptime(): number {
    if (this.connectTime === 0) return 0;
    return (Date.now() - this.connectTime) / 1000;
  }

  private getRestUrl(): string {
    return this.config?.restUrl ?? DEFAULT_REST_URL;
  }

  private toProductId(symbol: string): string {
    // BTC/USD -> BTC-USD
    return symbol.replace('/', '-');
  }

  private normalizeSymbol(productId: string): string {
    return productId.replace('-', '/');
  }

  private startHeartbeat(): void {
    this.stopHeartbeat();
    this.heartbeatTimer = setTimeout(() => {
      this.onHeartbeatTimeout();
    }, this.heartbeatTimeoutMs);
  }

  private resetHeartbeat(): void {
    if (this.heartbeatTimer !== undefined) {
      clearTimeout(this.heartbeatTimer);
      this.heartbeatTimer = setTimeout(() => {
        this.onHeartbeatTimeout();
      }, this.heartbeatTimeoutMs);
    }
  }

  private stopHeartbeat(): void {
    if (this.heartbeatTimer !== undefined) {
      clearTimeout(this.heartbeatTimer);
      this.heartbeatTimer = undefined;
    }
  }

  private onHeartbeatTimeout(): void {
    this.updateState('error', 'Heartbeat timeout');
    this.reconnect();
  }

  private clearTimers(): void {
    if (this.reconnectTimer !== undefined) {
      clearTimeout(this.reconnectTimer);
      this.reconnectTimer = undefined;
    }
    if (this.jwtRefreshTimer !== undefined) {
      clearInterval(this.jwtRefreshTimer);
      this.jwtRefreshTimer = undefined;
    }
  }
}
