import type { MessageNormalizer } from '../../normalization/pipeline';
import { parseNumeric, rfc3339ToMs } from '../../normalization/pipeline';
import type { NormalizedOHLCV, NormalizedOrderbook, NormalizedTick, NormalizedTrade } from '../../types/normalized';
import type {
  CoinbaseCandleEvent,
  CoinbaseL2Event,
  CoinbaseMarketTradeEvent,
  CoinbaseRawMessage,
  CoinbaseRestCandle,
  CoinbaseTickerEvent,
} from './coinbase-types';

/**
 * Normalizes raw Coinbase Advanced Trade WebSocket and REST messages.
 *
 * Handles:
 * - Event arrays (single message may contain multiple trades/candles)
 * - RFC 3339 timestamps -> ms epoch
 * - Numeric strings -> JavaScript numbers
 * - BTC-USD -> BTC/USD symbol normalization
 * - Sequence number tracking for gap detection
 */
export class CoinbaseNormalizer implements MessageNormalizer<CoinbaseRawMessage> {
  private lastSequenceNum = 0;

  parseMessage(raw: string): CoinbaseRawMessage | undefined {
    try {
      const parsed: unknown = JSON.parse(raw);
      if (typeof parsed !== 'object' || parsed === null) return undefined;
      if (!('channel' in parsed && 'events' in parsed)) return undefined;
      return parsed as CoinbaseRawMessage;
    } catch {
      return undefined;
    }
  }

  normalizeTicker(raw: CoinbaseRawMessage): NormalizedTick | undefined {
    if (raw.channel !== 'ticker') return undefined;
    const event = raw.events[0] as CoinbaseTickerEvent | undefined;
    if (!event) return undefined;
    const ticker = event.tickers[0];
    if (!ticker) return undefined;

    const lastPrice = parseNumeric(ticker.price);
    const changePercent = parseNumeric(ticker.price_percent_chg_24_h);
    const priceChange = lastPrice * (changePercent / 100);
    const symbol = this.normalizeSymbol(ticker.product_id);

    return {
      symbol,
      lastPrice,
      priceChange,
      priceChangePercent: changePercent,
      high24h: parseNumeric(ticker.high_24_h),
      low24h: parseNumeric(ticker.low_24_h),
      volume24h: parseNumeric(ticker.volume_24_h),
      quoteVolume24h: 0,
      timestamp: rfc3339ToMs(raw.timestamp),
      bestBid: parseNumeric(ticker.best_bid),
      bestBidQty: parseNumeric(ticker.best_bid_quantity),
      bestAsk: parseNumeric(ticker.best_ask),
      bestAskQty: parseNumeric(ticker.best_ask_quantity),
    };
  }

  normalizeTrade(raw: CoinbaseRawMessage): NormalizedTrade | undefined {
    if (raw.channel !== 'market_trades') return undefined;
    const event = raw.events[0] as CoinbaseMarketTradeEvent | undefined;
    if (!event) return undefined;
    const trade = event.trades[0];
    if (!trade) return undefined;

    const side = trade.side === 'BUY' ? 'buy' as const : 'sell' as const;
    return {
      id: trade.trade_id,
      timestamp: rfc3339ToMs(trade.time),
      price: parseNumeric(trade.price),
      quantity: parseNumeric(trade.size),
      side,
      buyerMaker: side === 'sell',
    };
  }

  normalizeOHLCV(raw: CoinbaseRawMessage): NormalizedOHLCV | undefined {
    if (raw.channel !== 'candles') return undefined;
    const event = raw.events[0] as CoinbaseCandleEvent | undefined;
    if (!event) return undefined;
    const candle = event.candles[0];
    if (!candle) return undefined;

    return {
      timestamp: rfc3339ToMs(candle.start),
      open: parseNumeric(candle.open),
      high: parseNumeric(candle.high),
      low: parseNumeric(candle.low),
      close: parseNumeric(candle.close),
      volume: parseNumeric(candle.volume),
      quoteVolume: 0,
      tradeCount: 0,
      closed: false,
    };
  }

  normalizeOrderbook(raw: CoinbaseRawMessage): NormalizedOrderbook | undefined {
    if (raw.channel !== 'level2') return undefined;
    const event = raw.events[0] as CoinbaseL2Event | undefined;
    if (!event) return undefined;

    const bids = event.updates
      .filter(u => u.side === 'bid')
      .map(u => ({
        price: parseNumeric(u.price_level),
        quantity: parseNumeric(u.new_quantity),
      }))
      .sort((a, b) => b.price - a.price);

    const asks = event.updates
      .filter(u => u.side === 'offer')
      .map(u => ({
        price: parseNumeric(u.price_level),
        quantity: parseNumeric(u.new_quantity),
      }))
      .sort((a, b) => a.price - b.price);

    return {
      symbol: this.normalizeSymbol(event.product_id),
      timestamp: rfc3339ToMs(raw.timestamp),
      bids,
      asks,
      sequenceId: raw.sequence_num,
      type: event.type === 'snapshot' ? 'snapshot' : 'delta',
    };
  }

  /** Normalize a REST candle into NormalizedOHLCV. */
  normalizeRestCandle(candle: CoinbaseRestCandle): NormalizedOHLCV {
    return {
      timestamp: rfc3339ToMs(candle.start),
      open: parseNumeric(candle.open),
      high: parseNumeric(candle.high),
      low: parseNumeric(candle.low),
      close: parseNumeric(candle.close),
      volume: parseNumeric(candle.volume),
      quoteVolume: 0,
      tradeCount: 0,
      closed: true,
    };
  }

  /** Check for sequence number gaps. Returns true if there is a gap. */
  hasSequenceGap(sequenceNum: number): boolean {
    if (this.lastSequenceNum === 0) {
      this.lastSequenceNum = sequenceNum;
      return false;
    }
    const hasGap = sequenceNum > this.lastSequenceNum + 1;
    this.lastSequenceNum = sequenceNum;
    return hasGap;
  }

  /** Reset the sequence tracker (e.g., after reconnection). */
  resetSequence(): void {
    this.lastSequenceNum = 0;
  }

  private normalizeSymbol(productId: string): string {
    return productId.replace('-', '/');
  }
}
